5	function failWith(message: string): never {
6	  process.stderr.write(`${message}\n`);
7	  process.exit(1);
8	}
9	
10	function countByType(entries: { type: string }[]): Map<string, number> {
11	  const counts = new Map<string, number>();
12	  for (const entry of entries) {
13	    counts.set(entry.type, (counts.get(entry.type) ?? 0) + 1);
14	  }
15	  return counts;
16	}
17	
18	const input = readFileSync(0, "utf-8");
19	const scenario = JSON.parse(input);
20	
21	const items: { type: string }[] = scenario.items ?? [];
22	for (const item of items) {
23	  if (!KNOWN_ITEM_TYPES.has(item.type)) {
24	    failWith(`unknown item type: ${item.type}`);
25	  }
26	}
27	
28	if (scenario.command === "claim") {
29	  const damages: { type: string; amount: number }[] = scenario.damages ?? [];
30	  for (const damage of damages) {
31	    if (damage.amount < 0) {
32	      failWith("negative damage amount");
33	    }
34	  }
35	  const policyCounts = countByType(items);
36	  const damageCounts = countByType(damages);
37	  for (const [type, count] of damageCounts) {
38	    if (!policyCounts.has(type)) {
39	      failWith(`damage type ${type} not in the policy`);
40	    }
41	    if (count > (policyCounts.get(type) ?? 0)) {
42	      failWith(`more damage entries of type ${type} than the policy covers`);
43	    }
44	  }
45	}
46	
47	const result = runScenario(scenario);
48	process.stdout.write(JSON.stringify(result) + "\n");
